  const receivedToken = authHeader.replace(/^Bearer\s+/i, '').trim();
  if (receivedToken !== EXPECTED_TOKEN) {
    return [{ json: { status: 'erro_auth', mensagem: 'Token invalido ou ausente.', codigo: 401 } }];
  }
}

