const texto_peticao = String(raw.texto_peticao || '').trim();
const modelo_base_texto = String(raw.modelo_base_texto || '').trim();
const tipo_acao_hint = String(raw.tipo_acao_hint || '').trim();
const pontos_contestante = String(raw.pontos_contestante || '').trim();
const usuario_id = String(raw.usuario_id || '').trim();
const dados_extraidos_pre_validados = (raw.dados_extraidos_pre_validados && typeof raw.dados_extraidos_pre_validados === 'object') ? raw.dados_extraidos_pre_validados : null;

// No modo revisao humana (HiL), o extrator e bypassado e os dados ja vem
// validados pelo advogado — texto_peticao nao e necessario.
if (!dados_extraidos_pre_validados) {
  if (!texto_peticao || texto_peticao.length < 50) {
    return [{ json: {
      status: 'erro_validacao',
      mensagem: 'texto_peticao obrigatorio com pelo menos 50 caracteres.',
      recebido_em: now
    }}];
  }

  if (texto_peticao.length > 100000) {
    return [{ json: {
      status: 'erro_validacao',
      mensagem: 'texto_peticao excede 100000 caracteres.',
      recebido_em: now
    }}];
  }
}

return [{ json: {
  status: 'entrada_validada',
  contexto: { texto_peticao, modelo_base_texto, tipo_acao_hint, pontos_contestante, usuario_id, dados_extraidos_pre_validados },
