      } else {
        const rows = await resp.json();
        if (!rows || rows.length === 0) {
          defesas_anteriores = { status: 'sem_resultados', detalhe: 'nenhuma defesa anterior', casos: [], total: 0 };
        } else {
          const queryTF = buildTF(tokenize((dados.fatos_resumo || '') + ' ' + (dados.pedidos || []).join(' ')));
          const casosRaw = rows.map(row => {
            const minuta = (row.n8n_resposta || {}).minuta || {};
            return {
              numero_processo: row.numero_processo,
              tipo_acao: row.tipo_acao,
              fatos: row.fatos || '',
              pedido_autor: row.pedido_autor || '',
              feedback_util: row.feedback_util,
              fatos_resumo: (row.fatos || '').slice(0, 500),
              pedido_autor_resumo: (row.pedido_autor || '').slice(0, 300),
              tese_central: minuta.tese_central || '',
              resumo_estrategico: minuta.resumo_estrategico || '',
              fundamentos_curtos: (minuta.fundamentos || '').slice(0, 1500),
              riscos: (minuta.riscos || []).slice(0, 3),
              criado_em: row.criado_em,
              _score: 0
            };
          });
